  (function () {
    window.addEventListener('load', () => {
      if (typeof gsap === 'undefined' || typeof ScrollTrigger === 'undefined') return;

      gsap.registerPlugin(ScrollTrigger);

      const prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

      const section = document.querySelector('[data-scroll="section"]');
      if (!section) return;

      const bg = section.querySelector('[data-scroll="bg"]');
      const container = section.querySelector('[data-scroll="container"]');
      const title = section.querySelector('.duraldar-cta_title');
      const subtitle = section.querySelector('[data-scroll="subtitle"]');
      const button = section.querySelector('[data-scroll="button"]');
      const asset = section.querySelector('.duraldar-cta-asset-image');
      const revealTargets = [title, asset, subtitle, button].filter(Boolean);

      const getStartState = () => {
        const prev = bg.style.cssText;
        bg.style.cssText = '';
        const cs = getComputedStyle(bg);
        const state = {
          maxWidth: cs.maxWidth,
          marginTop: cs.marginTop,
          marginBottom: cs.marginBottom,
          borderRadius: cs.borderRadius,
        };
        bg.style.cssText = prev;
        return state;
      };

      if (prefersReducedMotion) return;

      const HERO_DELAY_MS = 1400;

      setTimeout(() => {
        let scrubTriggers = [];
        let revealTimeline = null;

        const buildScrubAnimation = () => {
          scrubTriggers.forEach((t) => t.kill());
          scrubTriggers = [];

          if (!bg || !container) return;

          const startState = getStartState();
          const isMobile = window.matchMedia('(max-width: 479px)').matches;
          const containerMargin = isMobile ? '2rem' : '4rem';

          gsap.set(bg, startState);
          gsap.set(container, { marginTop: 0, marginBottom: 0 });

          const tl = gsap
            .timeline({
              scrollTrigger: {
                trigger: section,
                start: 'center 70%',
                end: 'center 40%',
                scrub: 0.8,
                invalidateOnRefresh: true,
              },
            })
            .fromTo(bg, startState, { maxWidth: '100%', marginTop: 0, marginBottom: 0, borderRadius: '0px', ease: 'power2.out' }, 0)
            .fromTo(container, { marginTop: 0, marginBottom: 0 }, { marginTop: containerMargin, marginBottom: containerMargin, ease: 'power2.out' }, 0.05);

          scrubTriggers.push(tl.scrollTrigger);
        };

        const buildRevealAnimation = () => {
          if (revealTimeline) {
            revealTimeline.scrollTrigger && revealTimeline.scrollTrigger.kill();
            revealTimeline.kill();
            revealTimeline = null;
          }

          if (!revealTargets.length) return;

          revealTimeline = gsap.timeline({
            scrollTrigger: {
              trigger: title || subtitle || section,
              start: 'top bottom',
              once: true,
            },
            defaults: { ease: 'power2.out' },
          });

          if (title) revealTimeline.to(title, { opacity: 1, y: '0%', duration: 0.7 }, 0);
          if (asset) revealTimeline.to(asset, { opacity: 1, y: '0%', duration: 0.7 }, 0);
          if (subtitle) revealTimeline.to(subtitle, { opacity: 1, y: '0%', duration: 0.6 }, '>-0.1');
          if (button) revealTimeline.to(button, { opacity: 1, y: '0%', duration: 0.6 }, '>-0.1');
        };

        buildScrubAnimation();
        buildRevealAnimation();
        ScrollTrigger.refresh();

        let resizeQueued = false;
        let lastWidth = window.innerWidth;

        window.addEventListener('resize', () => {
          if (resizeQueued) return;
          resizeQueued = true;

          requestAnimationFrame(() => {
            resizeQueued = false;
            if (window.innerWidth === lastWidth) return;
            lastWidth = window.innerWidth;

            buildScrubAnimation();

            if (revealTimeline && revealTimeline.scrollTrigger && !revealTimeline.scrollTrigger.progress) {
              buildRevealAnimation();
            }

            ScrollTrigger.refresh();
          });
        });
      }, HERO_DELAY_MS);
    });
  })();


